package main

import "fmt"

// This function returns both a string AND an int
func identifyGopher() (string, int) {
    name := "Bobby"
    age := 4

    // Returning both separated by a comma
    return name, age
}

func main() {
    // We MUST capture both returned values!
    n, a := identifyGopher()

    fmt.Printf("Gopher %s is %d years old.\n", n, a)
}
